const input = $input.first().json;
const data = input.data;
if (!data) return [{ json: { error: 'Parameter "data" is required (text or URL to encode).' } }];

const size = input.size || '300x300';
const encoded = encodeURIComponent(data);
const url = 'https://api.qrserver.com/v1/create-qr-code/?size=' + size + '&data=' + encoded + '&format=png';

// Verify the API is reachable
try {
  const response = await helpers.httpRequest({
    method: 'GET',
    url: url,
    returnFullResponse: true,
    encoding: 'arraybuffer',
    timeout: 10000
  });

  if (response.statusCode !== 200) {
    return [{ json: { error: 'QR code generation failed (HTTP ' + response.statusCode + ')' } }];
  }
} catch (err) {
  return [{ json: { error: 'QR code API unreachable: ' + err.message } }];
}

let result = 'QR Code generated!\n';
result += 'Image URL: ' + url + '\n';
result += 'Content: ' + data + '\n';
result += 'Size: ' + size + ' pixels';

return [{ json: { result } }];
